INSERT INTO import_tax_payment (
      pay_id
    , import_id
    , mem_id
    , officer_id
    , pay_status
    , total_amount
    , tax_base
    , duty_amt
    , vat_amt
    , issue_date
    , due_date
    , biz_reg_no
    , del_yn
    , remarks
    ) VALUES (
      #{payId}
    , #{importId}
    , #{memId}
    , #{officerId}
    , #{payStatus}
    , #{totalAmount}
    , #{taxBase}
    , #{dutyAmt}
    , #{vatAmt}
    , SYSDATE
    , SYSDATE + 15
    , #{bizRegNo}
    , 'N'
    , #{remarks}
)

